import type { PointsConfig } from '@smartcart/shared-types';
import type { SessionItem } from '../entities/shopping-session.entity';
import type { IPointsCalculationStrategy } from './points-calculation-strategy.interface';

/**
 * FIXED_PER_UNIT — `value * quantity` (README §2.3 Strategy Types table).
 */
export class FixedPointsStrategy implements IPointsCalculationStrategy {
  readonly strategyType = 'FIXED_PER_UNIT' as const;

  calculate(item: SessionItem, config: PointsConfig): number {
    if (config.type !== 'FIXED_PER_UNIT') {
      throw new Error('FixedPointsStrategy received a non-FIXED_PER_UNIT config');
    }
    return config.value * item.quantity;
  }
}
